static void writeJvmClass(JvmClass c, DataOutput out) throws IOException {
    writeInterfaces(c, out);
    writeFields(c, out);
}

static void writeInterfaces(JvmClass c, DataOutput out) throws IOException {
    int n = 0;
    for (String i : c.getInterfaces()) n++;
    DataInputOutputUtil.writeINT(out, n);
    for (String i : c.getInterfaces()) out.writeUTF(i);
}

static void writeFields(JvmClass c, DataOutput out) throws IOException {
    int m = 0;
    for (JvmField f : c.getFields()) m++;
    DataInputOutputUtil.writeINT(out, m);
    for (JvmField f : c.getFields()) writeJvmField(f, out);
}

